// src/components/BookPage.jsx
//
// All visual properties are driven by `page.style`.
// reference.learnMore is optional — the "Learn More" link is hidden when omitted.
// No scrolling — layout is fixed to the page dimensions.

export default function BookPage({ page, pageNum, total, onShowRef, pageW, pageH }) {
  const isCover = page.type === "cover";
  const isEnd   = page.type === "end";

  // ─── scale helper ──────────────────────────────────────────────────────────
  const scale = Math.min(pageW / 380, pageH / 500, 1.6);
  const em = (base) => Math.round(base * scale);

  // ─── unpack style with defaults ────────────────────────────────────────────
  const s = page.style || {};

  // typography
  const fontFamily      = s.fontFamily      || "'Bubblegum Sans', cursive";
  const titleFontFamily = s.titleFontFamily || fontFamily;
  const textFontFamily  = s.textFontFamily  || fontFamily;
  const titleAlign      = s.titleAlign  || "center";
  const textAlign       = s.textAlign   || "center";
  const titleWeight     = s.titleWeight !== undefined ? s.titleWeight : 800;
  const titleItalic     = s.titleItalic || false;

  // layout
  const gap      = s.gap !== undefined ? s.gap : 12;
  const [pV, pH] = s.padding || [24, 20];

  // image — explicit W/H override shorthand imageSize
 
  const imageW       = s.imageW    !== undefined ? s.imageW    : (s.imageSize || defaultSize);
  const imageH       = s.imageH    !== undefined ? s.imageH    : (s.imageSize || defaultSize);
  const imageFit     = s.imageFit     || "contain";
  const imagePos     = s.imagePosition || "center";
  const imageRepeat  = s.imageRepeat   || "no-repeat";  // used when image is a bg; noted for completeness
  const imageRadius  = s.imageRadius  !== undefined ? s.imageRadius  : 0;
  const imageBorder  = s.imageBorder  || "none";
  const imageShadow  = s.imageShadow  !== undefined
    ? s.imageShadow
    : "0 4px 12px rgba(0,0,0,0.15)";
  const imageMaxW    = s.imageMaxW || "90%";

  // text card
  const cardBg     = s.cardBg     || "rgba(255,255,255,0.28)";
  const cardRadius  = s.cardRadius !== undefined ? s.cardRadius : 18;
  const cardBorder  = s.cardBorder || "none";
  const [cV, cH]    = s.cardPadding || [14, 18];

  // facts panel
  const factsBg     = s.factsBg     || "rgba(255,255,255,0.25)";
  const factsRadius = s.factsRadius !== undefined ? s.factsRadius : 14;
  const factsBorder = s.factsBorder || "none";

  // page chrome
  const pageBorder     = s.pageBorder     || "none";
  const overlayCircles = s.overlayCircles !== false;

  // ─── content order ─────────────────────────────────────────────────────────
  const defaultOrder = ["image", "title", "subtitle", "text", "facts", "emoji"];
  const contentOrder  = s.contentOrder || defaultOrder;

  // ─── block renderers ───────────────────────────────────────────────────────
  const blocks = {

    // IMAGE (or emoji fallback)
    image: page.image ? (
      <img
        key="image"
        src={page.image}
        alt={page.title}
        style={{
          width: em(imageW),
          height: em(imageH),
          maxWidth: imageMaxW,
          objectFit: imageFit,
          objectPosition: imagePos,
          borderRadius: em(imageRadius),
          border: imageBorder,
          // imageShadow supports multi-shadow strings (comma-separated)
          filter: imageShadow
            ? imageShadow.split(",").map(sh => `drop-shadow(${sh.trim()})`).join(" ")
            : "none",
          flexShrink: 0,
          display: "block",
        }}
      />
    ) : (
      <div
        key="image"
        style={{
          fontSize: em(isCover || isEnd ? 88 : 68),
          lineHeight: 1,
          flexShrink: 0,
        }}
      >
        {page.emoji || "📖"}
      </div>
    ),

    // TITLE
    title: (
      <div
        key="title"
        style={{
          fontFamily: titleFontFamily,
          fontSize: em(page.titleSize || (isCover || isEnd ? page.fontSize || 32 : 24)),
          fontWeight: titleWeight,
          fontStyle: titleItalic ? "italic" : "normal",
          textAlign: titleAlign,
          lineHeight: 1.2,
          textShadow: "0 2px 10px rgba(0,0,0,0.18)",
          letterSpacing: isCover ? "0.04em" : "0.01em",
          width: "100%",
          flexShrink: 0,
        }}
      >
        {page.title}
      </div>
    ),

    // SUBTITLE
    subtitle: page.subtitle ? (
      <div
        key="subtitle"
        style={{
          fontFamily,
          fontSize: em(17),
          opacity: 0.92,
          textAlign: titleAlign,
          fontStyle: "italic",
          width: "100%",
          flexShrink: 0,
        }}
      >
        {page.subtitle}
      </div>
    ) : null,

    // BODY TEXT CARD
    text: page.text ? (
      <div
        key="text"
        style={{
          fontFamily: textFontFamily,
          fontSize: em(page.fontSize || 17),
          textAlign,
          lineHeight: 1.7,
          maxWidth: em(320),
          width: "100%",
          background: cardBg,
          borderRadius: em(cardRadius),
          border: cardBorder,
          padding: `${em(cV)}px ${em(cH)}px`,
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          flexShrink: 0,
        }}
      >
        {page.text}
      </div>
    ) : null,

    // FACTS PANEL
    facts: page.reference?.facts?.length > 0 ? (
      <div
        key="facts"
        style={{
          fontFamily: textFontFamily,
          background: factsBg,
          borderRadius: em(factsRadius),
          border: factsBorder,
          padding: `${em(10)}px ${em(12)}px`,
          width: "92%",
          maxWidth: em(330),
          backdropFilter: "blur(4px)",
          boxSizing: "border-box",
          flexShrink: 0,
        }}
      >
        <h3
          style={{
            margin: `0 0 ${em(6)}px 0`,
            textAlign: "center",
            fontSize: em(14),
            fontFamily: titleFontFamily,
          }}
        >
          📚 Did You Know?
        </h3>
        <ul
          style={{
            margin: 0,
            paddingLeft: em(16),
            fontSize: em(12),
            lineHeight: 1.5,
          }}
        >
          {page.reference.facts.map((fact, i) => (
            <li key={i} style={{ marginBottom: em(4) }}>
              {fact}
            </li>
          ))}
        </ul>
        {/* learnMore is optional — only rendered when present */}
        {page.reference.learnMore && (
          <div style={{ marginTop: em(8), textAlign: "center" }}>
            <a
              href={page.reference.learnMore}
              target="_blank"
              rel="noreferrer"
              style={{
                color: page.textColor || "#333",
                fontWeight: "bold",
                fontSize: em(12),
                textDecoration: "underline",
              }}
            >
              Learn More →
            </a>
          </div>
        )}
      </div>
    ) : null,

    // EMOJI
    emoji: page.emoji ? (
      <div
        key="emoji"
        style={{ fontSize: em(40), flexShrink: 0 }}
      >
        {page.emoji}
      </div>
    ) : null,
  };

  // ─── render ────────────────────────────────────────────────────────────────
  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        background: page.bg || "#fff",
        color: page.textColor || "#333",
        border: pageBorder,
        // NO scroll — fixed to page dimensions
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: em(gap),
        padding: `${em(pV)}px ${em(pH)}px`,
        boxSizing: "border-box",
        fontFamily,
        position: "relative",
        userSelect: "none",
      }}
    >
      {/* ── Decorative corner circles (toggleable) ── */}
      {overlayCircles && (
        <>
          <div
            style={{
              position: "absolute",
              top: em(-45),
              left: em(-45),
              width: em(140),
              height: em(140),
              borderRadius: "50%",
              background: "rgba(255,255,255,0.13)",
              pointerEvents: "none",
            }}
          />
          <div
            style={{
              position: "absolute",
              bottom: em(-30),
              right: em(-30),
              width: em(100),
              height: em(100),
              borderRadius: "50%",
              background: "rgba(255,255,255,0.10)",
              pointerEvents: "none",
            }}
          />
        </>
      )}

      {/* ── Learn button ── */}
      {page.reference && (
        <button
          onClick={() => onShowRef?.(page.reference)}
          style={{
            position: "absolute",
            top: em(10),
            left: em(10),
            background: "rgba(255,255,255,0.28)",
            border: "1px solid rgba(255,255,255,0.55)",
            borderRadius: em(20),
            padding: `${em(4)}px ${em(10)}px`,
            cursor: "pointer",
            fontSize: em(12),
            fontWeight: 700,
            color: page.textColor || "#333",
            backdropFilter: "blur(4px)",
            boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
            fontFamily,
          }}
        >
          🔍 Learn
        </button>
      )}

     

      {/* ── Ordered content blocks ── */}
      {contentOrder.map((token) => blocks[token] ?? null)}

      {/* ── Page number ── */}
      {!isCover && (
        <div
          style={{
            position: "absolute",
            bottom: em(8),
            fontSize: em(11),
            opacity: 0.5,
            fontFamily: "'Nunito', sans-serif",
          }}
        >
          {pageNum} / {total-1}
        </div>
      )}
    </div>
  );
}
